--
-- Intro to Postgres - Series 05 Sample Data
--
-- This file creates and populates tables for learning JSON/JSONB:
-- - users_json: JSON type (preserves whitespace, duplicate keys)
-- - users_jsonb: JSONB type (normalized, efficient queries)
-- - products: JSONB metadata with nested objects
-- - events: JSONB with UUIDs for generated columns demo
--
-- Usage: Run this file in any SQL client (TablePlus, pgAdmin, etc.)
--

-- Clean up if tables exist
DROP TABLE IF EXISTS events CASCADE;
DROP TABLE IF EXISTS products CASCADE;
DROP TABLE IF EXISTS users_jsonb CASCADE;
DROP TABLE IF EXISTS users_json CASCADE;

--
-- Users with JSON type (preserves formatting, duplicate keys)
--

CREATE TABLE users_json (
    id integer PRIMARY KEY GENERATED BY DEFAULT AS IDENTITY,
    data json NOT NULL
);

--
-- Users with JSONB type (normalized, indexable)
--

CREATE TABLE users_jsonb (
    id integer PRIMARY KEY GENERATED BY DEFAULT AS IDENTITY,
    data jsonb NOT NULL
);

--
-- Products table with JSONB metadata
--

CREATE TABLE products (
    id integer PRIMARY KEY GENERATED BY DEFAULT AS IDENTITY,
    name text NOT NULL,
    metadata jsonb NOT NULL
);

--
-- Events table for generated columns demo
--

CREATE TABLE events (
    id integer PRIMARY KEY GENERATED BY DEFAULT AS IDENTITY,
    event_type text NOT NULL,
    metadata jsonb NOT NULL,
    created_at timestamp(0) without time zone DEFAULT now() NOT NULL
);

-- Products data


-- Events data

--
-- Reset identity sequences
--

SELECT setval(pg_get_serial_sequence('products', 'id'), COALESCE((SELECT MAX(id) FROM products), 1), true);
SELECT setval(pg_get_serial_sequence('events', 'id'), COALESCE((SELECT MAX(id) FROM events), 1), true);
